@namespace Lumeo

@{
    var context = new DropdownMenuContext(Open, EventCallback.Factory.Create<bool>(this, SetOpen), _wrapperId, _contentId);
}

<CascadingValue Value="context" IsFixed="false">
    <div id="@_wrapperId" class="relative inline-block" @attributes="AdditionalAttributes">
        @ChildContent
    </div>
</CascadingValue>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public bool Open { get; set; }
    [Parameter] public EventCallback<bool> OpenChanged { get; set; }

    [Obsolete("Use Open instead. IsOpen will be removed in a future release.")]
    [Parameter] public bool IsOpen { get => Open; set => Open = value; }

    [Obsolete("Use OpenChanged instead. IsOpenChanged will be removed in a future release.")]
    [Parameter] public EventCallback<bool> IsOpenChanged { get => OpenChanged; set => OpenChanged = value; }

    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _wrapperId = $"dropdown-{Guid.NewGuid():N}";
    // Stable content id shared with trigger via context for aria-controls
    internal readonly string _contentId = $"dropdown-content-{Guid.NewGuid():N}";

    private async Task SetOpen(bool value)
    {
        Open = value;
        await OpenChanged.InvokeAsync(value);
    }

    public record DropdownMenuContext(bool IsOpen, EventCallback<bool> SetOpen, string WrapperId, string ContentId);
}

@namespace Lumeo

<button type="button" role="menuitemcheckbox" aria-checked="@Checked.ToString().ToLower()" tabindex="-1" class="@CssClass" @onclick="Toggle" @attributes="AdditionalAttributes">
    <span class="flex h-3.5 w-3.5 items-center justify-center">
        @if (Checked)
        {
            <Blazicon Svg="Lucide.Check" class="h-3.5 w-3.5" />
        }
    </span>
    @ChildContent
</button>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public bool Checked { get; set; }
    [Parameter] public EventCallback<bool> CheckedChanged { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"relative flex w-full cursor-default select-none items-center gap-2 rounded-sm py-1.5 pl-8 pr-2 text-sm outline-none transition-colors hover:bg-accent hover:text-accent-foreground focus:bg-accent focus:text-accent-foreground {Class}".Trim();

    private async Task Toggle()
    {
        Checked = !Checked;
        await CheckedChanged.InvokeAsync(Checked);
    }
}

@namespace Lumeo
@implements IAsyncDisposable

@if (Context.IsOpen)
{
    <div id="@Context.ContentId"
         role="menu"
         aria-orientation="vertical"
         class="@CssClass"
         @onkeydown="HandleKeyDown"
         tabindex="-1"
         @attributes="AdditionalAttributes">
        @ChildContent
        @if (ShowArrow)
        {
            <div class="@ArrowClasses"></div>
        }
    </div>
}

@inject ComponentInteropService Interop

@code {
    [CascadingParameter] public DropdownMenu.DropdownMenuContext Context { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public DropdownMenuAlign Align { get; set; } = DropdownMenuAlign.Start;
    [Parameter] public DropdownMenuSide Side { get; set; } = DropdownMenuSide.Bottom;
    [Parameter] public bool ShowArrow { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool _registered;
    private int _focusedIndex = -1;

    private string CssClass => string.Join(" ", new[] { "fixed z-50 min-w-[8rem] rounded-md border border-border/60 bg-popover p-1 text-popover-foreground shadow-lg animate-fade-in", ShowArrow ? "overflow-visible" : "overflow-hidden", Class }.Where(s => !string.IsNullOrWhiteSpace(s)));

    private string ArrowClasses => Side switch
    {
        DropdownMenuSide.Top => "absolute left-1/2 top-full -translate-x-1/2 -translate-y-1/2 rotate-45 h-2.5 w-2.5 bg-popover border-b border-r border-border/60",
        DropdownMenuSide.Bottom => "absolute left-1/2 bottom-full -translate-x-1/2 translate-y-1/2 rotate-45 h-2.5 w-2.5 bg-popover border-t border-l border-border/60",
        DropdownMenuSide.Left => "absolute top-1/2 left-full -translate-y-1/2 -translate-x-1/2 rotate-45 h-2.5 w-2.5 bg-popover border-t border-r border-border/60",
        DropdownMenuSide.Right => "absolute top-1/2 right-full -translate-y-1/2 translate-x-1/2 rotate-45 h-2.5 w-2.5 bg-popover border-b border-l border-border/60",
        _ => "absolute left-1/2 bottom-full -translate-x-1/2 translate-y-1/2 rotate-45 h-2.5 w-2.5 bg-popover border-t border-l border-border/60"
    };

    private string AlignStr => Align switch
    {
        DropdownMenuAlign.Start => "start",
        DropdownMenuAlign.Center => "center",
        DropdownMenuAlign.End => "end",
        _ => "start"
    };

    private string SideStr => Side switch
    {
        DropdownMenuSide.Top => "top",
        DropdownMenuSide.Left => "left",
        DropdownMenuSide.Right => "right",
        _ => "bottom"
    };

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (Context.IsOpen && !_registered)
        {
            await Interop.PositionFixed(Context.ContentId, Context.WrapperId, AlignStr, false, SideStr);
            await Interop.RegisterClickOutside(Context.ContentId, null, async () =>
            {
                await Context.SetOpen.InvokeAsync(false);
                await InvokeAsync(StateHasChanged);
            });
            _registered = true;
            _focusedIndex = -1;

            // Move focus to the menu container so Escape/ArrowUp/ArrowDown reach
            // the @onkeydown handler. Without this, focus stays on the trigger
            // button and keyboard nav silently breaks (per WAI-ARIA menu pattern).
            try { await Interop.FocusElement(Context.ContentId); } catch (JSDisconnectedException) { }
        }
        else if (!Context.IsOpen && _registered)
        {
            await Cleanup();
        }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        switch (e.Key)
        {
            case "Escape":
                await Context.SetOpen.InvokeAsync(false);
                break;
            case "ArrowDown":
                {
                    var count = await Interop.GetMenuItemCount(Context.ContentId);
                    if (count > 0)
                    {
                        _focusedIndex = (_focusedIndex + 1) % count;
                        await Interop.FocusMenuItemByIndex(Context.ContentId, _focusedIndex);
                    }
                    break;
                }
            case "ArrowUp":
                {
                    var count = await Interop.GetMenuItemCount(Context.ContentId);
                    if (count > 0)
                    {
                        _focusedIndex = _focusedIndex <= 0 ? count - 1 : _focusedIndex - 1;
                        await Interop.FocusMenuItemByIndex(Context.ContentId, _focusedIndex);
                    }
                    break;
                }
            case "Home":
                {
                    var count = await Interop.GetMenuItemCount(Context.ContentId);
                    if (count > 0)
                    {
                        _focusedIndex = 0;
                        await Interop.FocusMenuItemByIndex(Context.ContentId, _focusedIndex);
                    }
                    break;
                }
            case "End":
                {
                    var count = await Interop.GetMenuItemCount(Context.ContentId);
                    if (count > 0)
                    {
                        _focusedIndex = count - 1;
                        await Interop.FocusMenuItemByIndex(Context.ContentId, _focusedIndex);
                    }
                    break;
                }
        }
    }

    private async Task Cleanup()
    {
        try { await Interop.UnpositionFixed(Context.ContentId); } catch (JSDisconnectedException) { }
        try { await Interop.UnregisterClickOutside(Context.ContentId); } catch (JSDisconnectedException) { }
        _registered = false;
    }

    public async ValueTask DisposeAsync()
    {
        if (_registered) await Cleanup();
    }

    public enum DropdownMenuAlign { Start, Center, End }
    public enum DropdownMenuSide { Top, Bottom, Left, Right }
}

@namespace Lumeo

<div role="group" aria-label="@AriaLabel" class="@CssClass" @attributes="AdditionalAttributes">
    @ChildContent
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? AriaLabel { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"{Class}".Trim();
}

@namespace Lumeo

<button class="@CssClass" role="menuitem" tabindex="-1" @onclick="HandleClick" disabled="@Disabled" @attributes="AdditionalAttributes">
    @ChildContent
</button>

@code {
    [CascadingParameter] public DropdownMenu.DropdownMenuContext? Context { get; set; }
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public EventCallback OnClick { get; set; }
    [Parameter] public bool Disabled { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"relative flex w-full cursor-pointer select-none items-center gap-2 rounded-sm px-2 py-1.5 min-h-11 sm:min-h-0 text-sm outline-none transition-colors hover:bg-accent hover:text-accent-foreground focus:bg-accent focus:text-accent-foreground disabled:pointer-events-none disabled:opacity-50 disabled:cursor-not-allowed {Class}".Trim();

    private async Task HandleClick()
    {
        await OnClick.InvokeAsync();
        if (Context is not null)
        {
            await Context.SetOpen.InvokeAsync(false);
        }
    }
}

@namespace Lumeo

<div class="@CssClass" @attributes="AdditionalAttributes">
    @ChildContent
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"px-2 py-1.5 text-sm font-semibold {Class}".Trim();
}

@namespace Lumeo

@{
    var context = new DropdownMenuRadioGroupContext(Value, EventCallback.Factory.Create<string>(this, OnValueSelected));
}

<CascadingValue Value="context" IsFixed="false">
    <div role="group" @attributes="AdditionalAttributes">
        @ChildContent
    </div>
</CascadingValue>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Value { get; set; }
    [Parameter] public EventCallback<string> ValueChanged { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private async Task OnValueSelected(string value)
    {
        Value = value;
        await ValueChanged.InvokeAsync(value);
    }

    public record DropdownMenuRadioGroupContext(string? Value, EventCallback<string> OnSelect);
}

@namespace Lumeo

<button type="button" role="menuitemradio" aria-checked="@IsSelected.ToString().ToLower()" tabindex="-1" class="@CssClass" @onclick="Select" @attributes="AdditionalAttributes">
    <span class="flex h-3.5 w-3.5 items-center justify-center">
        @if (IsSelected)
        {
            <Blazicon Svg="Lucide.Circle" class="h-2 w-2 fill-current" />
        }
    </span>
    @ChildContent
</button>

@code {
    [CascadingParameter] public DropdownMenuRadioGroup.DropdownMenuRadioGroupContext Context { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter, EditorRequired] public string Value { get; set; } = "";
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool IsSelected => Context.Value == Value;

    private string CssClass => $"relative flex w-full cursor-default select-none items-center gap-2 rounded-sm py-1.5 pl-8 pr-2 text-sm outline-none transition-colors hover:bg-accent hover:text-accent-foreground focus:bg-accent focus:text-accent-foreground {Class}".Trim();

    private async Task Select() => await Context.OnSelect.InvokeAsync(Value);
}

@namespace Lumeo

<div class="@CssClass" role="none" @attributes="AdditionalAttributes"></div>

@code {
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"-mx-1 my-1 h-px bg-border {Class}".Trim();
}

@namespace Lumeo

@* The `group` class + `data-state` attribute let consumers rotate a chevron on open with
   `group-data-[state=open]:rotate-180` on any descendant icon — no EventCallbacks or bindings needed. *@
<div id="@_triggerId"
     class="@CssClass"
     role="button"
     data-state="@(Context.IsOpen ? "open" : "closed")"
     aria-haspopup="menu"
     aria-expanded="@Context.IsOpen.ToString().ToLower()"
     aria-controls="@Context.ContentId"
     @onclick="Toggle"
     @attributes="AdditionalAttributes">
    @ChildContent
</div>

@code {
    [CascadingParameter] public DropdownMenu.DropdownMenuContext Context { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    internal string TriggerId => _triggerId;
    private readonly string _triggerId = $"dropdown-trigger-{Guid.NewGuid():N}";

    private string CssClass => $"group inline-flex {Class}".Trim();

    private async Task Toggle() => await Context.SetOpen.InvokeAsync(!Context.IsOpen);
}
